import numpy as np
import math

# Given strikes and implied vols
K = np.array([800, 850, 900, 950, 1000, 1050, 1100, 1150, 1200], dtype=float)
iv = np.array([0.20, 0.205, 0.21, 0.215, 0.22, 0.225, 0.23, 0.235, 0.24], dtype=float)

# Assumptions consistent with typical setup of the referenced example:
# Spot equals ATM strike; zero rates/dividends; 6 months to maturity; notional $100 million.
S0 = 1000.0
r = 0.0
q = 0.0
T = 0.5
notional = 100e6

def norm_cdf(x):
    return 0.5 * (1.0 + math.erf(x / math.sqrt(2.0)))

def bs_call_price(S, K, T, r, q, sigma):
    if T <= 0:
        return max(S - K, 0.0)
    if sigma <= 0:
        fwd = S * math.exp((r - q) * T)
        disc = math.exp(-r * T)
        return disc * max(fwd - K, 0.0)
    d1 = (math.log(S / K) + (r - q + 0.5 * sigma * sigma) * T) / (sigma * math.sqrt(T))
    d2 = d1 - sigma * math.sqrt(T)
    return S * math.exp(-q * T) * norm_cdf(d1) - K * math.exp(-r * T) * norm_cdf(d2)

def bs_put_price(S, K, T, r, q, sigma):
    if T <= 0:
        return max(K - S, 0.0)
    if sigma <= 0:
        fwd = S * math.exp((r - q) * T)
        disc = math.exp(-r * T)
        return disc * max(K - fwd, 0.0)
    d1 = (math.log(S / K) + (r - q + 0.5 * sigma * sigma) * T) / (sigma * math.sqrt(T))
    d2 = d1 - sigma * math.sqrt(T)
    return K * math.exp(-r * T) * norm_cdf(-d2) - S * math.exp(-q * T) * norm_cdf(-d1)

# OTM option prices: puts for K < F, calls for K > F; ignore ATM point
F0 = S0 * math.exp((r - q) * T)
disc = math.exp(-r * T)

otm_prices = []
otm_strikes = []
for k, s in zip(K, iv):
    if k < F0:
        otm_prices.append(bs_put_price(S0, k, T, r, q, s))
        otm_strikes.append(k)
    elif k > F0:
        otm_prices.append(bs_call_price(S0, k, T, r, q, s))
        otm_strikes.append(k)
    # skip ATM strike

otm_prices = np.array(otm_prices, dtype=float)
otm_strikes = np.array(otm_strikes, dtype=float)

# Discrete replication for variance swap strike (Carr-Madan style):
# K_var = (2*e^{rT}/T) * sum( ΔK / K^2 * OTM_option_price )
# with ΔK for interior points as (K_{i+1}-K_{i-1})/2, endpoints as forward/backward difference
idx = np.argsort(otm_strikes)
otm_strikes = otm_strikes[idx]
otm_prices = otm_prices[idx]

dK = np.zeros_like(otm_strikes)
for i in range(len(otm_strikes)):
    if i == 0:
        dK[i] = otm_strikes[i+1] - otm_strikes[i]
    elif i == len(otm_strikes) - 1:
        dK[i] = otm_strikes[i] - otm_strikes[i-1]
    else:
        dK[i] = 0.5 * (otm_strikes[i+1] - otm_strikes[i-1])

K_var = (2.0 * math.exp(r * T) / T) * np.sum(dK * otm_prices / (otm_strikes ** 2))

# Fair variance swap value at initiation is ~0; interpret question as variance notional payout per unit variance:
# Value (in $) for receiving realized variance and paying fixed K_var is not determinable without realized variance.
# So compute the variance swap strike in variance points and translate to $ using variance notional = notional.
# Common convention: payout = notional * (realized_var - K_var). Here report notional * K_var in millions.
value_millions = (notional * K_var) / 1e6

print(value_millions)

